const ANNOUNCEMENTS = [
  {
    id: 1,
    text: "🔥 ¡Oferta de Verano! 50% de descuento en el primer alquiler",
    link: "/#",
    color: "bg-gradient-to-r from-orange-500/20 to-red-500/20",
